import { FacebookTournament } from '@/FBInstantExtra'
import {
    getLeaderboardAsync,
    getPlayerEntryTournamentAsync,
} from '@/modules/tournament/api/leaderboards'
import TournamentNotFound from '../exceptions/TournamentNotFound'
import SameContext from '../exceptions/SameContext'

const { LeadersBoard, Tournament } = GameCore.Configs
const { LeaderboardId, Limit } = LeadersBoard
const { YourMockTournamentCount } = Tournament
const FIRST_TOURNAMENT_ID = 1

class TournamentMock implements FBInstant.Tournament {
    private id: number
    private title: string
    private contextId: string
    private payload: string
    private endTime: number
    private initialScore: number

    constructor(id: number) {
        this.id = id
        this.title = `${this.id}'s Tournament`
        this.contextId = '000-' + this.id
        this.initialScore = 0

        this.payload = JSON.stringify({
            playerId: '1213456',
            playerName: 'Player',
            leaderboardId: LeaderboardId,
        })

        // * End time is max in 7 days
        // ? format: getEndTime of sdk fb

        const days = id > 7 ? 7 : id
        this.endTime = Math.round((Date.now() + 1000 * 60 * 60 * 24 * days) / 1000)
    }

    public getID(): number {
        return this.id
    }

    public getTitle(): string {
        return this.title
    }

    public getPayload(): string | null {
        return this.payload
    }

    public getEndTime(): number {
        return this.endTime
    }

    public getContextID(): string {
        return this.contextId
    }

    public getInitialScore(): number {
        return this.initialScore
    }

    public setCreatePayload({ initialScore, config, data }: FBInstant.CreateTournamentPayload) {
        this.initialScore = initialScore

        if (config) {
            this.title = config.tournamentTitle
        }

        if (data) {
            this.payload = JSON.stringify(data)
        }
    }
}

class MockFacebookTournament extends FacebookTournament {
    private tournaments: FBInstant.Tournament[]
    private tournamentData: Record<string, FBInstant.Tournament>

    constructor() {
        super()

        const firstTournament = new TournamentMock(FIRST_TOURNAMENT_ID)
        this.tournaments = [firstTournament]

        this.tournamentData = {
            [FIRST_TOURNAMENT_ID.toString()]: firstTournament,
        }

        this.createYourMockTournaments()
    }

    public async createAsync(
        payload: FBInstant.CreateTournamentPayload
    ): Promise<FBInstant.Tournament> {
        return new Promise((resolve) => {
            const id = this.tournaments.length + 1
            const newTournament = new TournamentMock(id)

            newTournament.setCreatePayload(payload)

            this.tournaments.push(newTournament)
            this.tournamentData[id] = newTournament

            resolve(newTournament)
        })
    }

    public async shareAsync(_payload: FBInstant.ShareTournamentPayload): Promise<void> {
        return new Promise((resolve) => resolve())
    }

    public async joinAsync(tournamentID: string): Promise<void> {
        const isExist = tournamentID in this.tournamentData

        if (!isExist) {
            return this.getPromiseRejectTournamentNotFound()
        }

        const tournament = this.tournamentData[tournamentID]
        const contextID = tournament.getContextID()

        if (contextID === FBInstant.context.getID()) {
            return Promise.reject(new SameContext(null))
        }

        try {
            await this.validateTournament(tournament)
            await GameCore.Utils.Valid.isValueChangeAsync(window.__fbGameReady, true)
            await FBInstant.context.switchAsync(tournamentID)
        } catch (error) {
            return Promise.reject(error)
        }

        return Promise.resolve()
    }

    private async validateTournament(tournament: FBInstant.Tournament) {
        const payload = tournament.getPayload()
        const { leaderboardId } = JSON.parse(payload)

        let leaders = []

        try {
            leaders = await getLeaderboardAsync(leaderboardId, { limit: Limit })
        } catch (error) {
            return Promise.reject(error)
        }

        if (leaders.length === 0) {
            return this.getPromiseRejectTournamentNotFound()
        }

        const playerId = window.game.player.getPlayerId()
        const playerInLeaders = leaders.find((leader) => leader.playerId === playerId)

        if (!playerInLeaders) {
            return this.getPromiseRejectTournamentNotFound()
        }

        let playerEntry = null

        try {
            playerEntry = await getPlayerEntryTournamentAsync(playerId, leaderboardId)
        } catch (error) {
            return Promise.reject(error)
        }

        if (!playerEntry) {
            return this.getPromiseRejectTournamentNotFound()
        }

        return Promise.resolve()
    }

    private getPromiseRejectTournamentNotFound() {
        return Promise.reject(new TournamentNotFound(null))
    }

    public async postScoreAsync(_score: number): Promise<void> {
        return Promise.resolve()
    }

    public async getTournamentsAsync(): Promise<FBInstant.Tournament[]> {
        const tournaments = [...this.tournaments]
        return tournaments
    }

    private createYourMockTournaments() {
        const { playerId, name } = window.game.player.getPlayer()

        for (let i = 0; i < YourMockTournamentCount; i++) {
            const id = FIRST_TOURNAMENT_ID + i + 1
            const tournament = new TournamentMock(id)

            tournament.setCreatePayload({
                initialScore: 0,
                config: {
                    tournamentTitle: name + " 's Tournament",
                },
                data: {
                    playerId,
                    playerName: name,
                    leaderboardId: LeaderboardId,
                },
            })

            this.tournaments.push(tournament)
            this.tournamentData[id] = tournament
        }
    }
}

export default MockFacebookTournament
